var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"STUDENT_EXTRA_B_NULL","text":{"KOREA":"와아……. 진짜 저런 복장으로 다니는구나.","JPN":"わあ……マジであんな格好してるんだ。","ENG":"Woah… So they really do go around in that clown outfit.","TWN":"哇賽……竟然真的會有人穿那種衣服上街？！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"STUDENT_EXTRA_A_NULL","text":{"KOREA":"야, 쟤네 보나마나 왕창 깨지겠지? 영상 찍고 있지?","JPN":"まあ、あいつらもどうせボコボコにやられるでしょ？　動画撮ってる？","ENG":"They're probably going to get their butt kicked, right? Are you recording this?","TWN":"喂，他們會死得很慘吧？你有拍下來嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STUDENT_EXTRA_B_NULL","text":{"KOREA":"그럼. 기껏 피난 안 가고 숨어 있었는데. 이건 건져야지.","JPN":"もちろん。このためにわざわざ避難しないで隠れてたし、ちゃんと撮っておかないと。","ENG":"Of course! This is exactly why we decided to hide instead of evacuate. I can't miss this.","TWN":"那當然！放棄逃難躲在這裡，當然要撈點好處！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"STUDENT_EXTRA_A_NULL","text":{"KOREA":"히히. 저 꼴로 싸우다 개박살 나면 넷튜브 웃음 토픽 감이겠다, 진짜.","JPN":"ひひひ。あんな格好で戦って、ボロクソに負けたらネットチューブのコメディ部門でトピックになりそうだな。","ENG":"Haha. They'll be a total laughing stock on NetTube if they lose wearing those outfits.","TWN":"嘿嘿，他們那樣盛裝打扮，到時候打輸的話，一定會成為網友的笑料！笑死！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"흐앙……. 배에서 꼬르륵 소리 나…….","JPN":"ふえぇ……お腹がぐうぐう鳴ってる……","ENG":"Aw… My stomach is growling…","TWN":"嗚……我的肚子在咕嚕叫……"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"부단장, 우리 언제까지 여기서 폼 잡고 있어야 돼?","JPN":"副団長、私たちいつまでここで格好つけてなきゃいけないの？","ENG":"Deputy Commander. How long do we have to stand here like medieval cosplayers gone too far?","TWN":"副團長，我們要在這裡擺POSE到什麼時候？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"리브 경, 같은 기사단원으로서 그 평가는 그냥 넘어갈 수 없군요.","JPN":"アレン卿、同じ騎士団員としてその発言は見過ごせませんね。","ENG":"Dame Liv, as a fellow knight of the Order of Zodiac, I cannot simply ignore such irreverence from you.","TWN":"莉芙卿，同樣身為騎士團團員，我必須好好說說你。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"저희들이 비까지 맞으면서 이곳을 지키는 이유는 수배자의 목적지로 유력한 제프티 바이오테크의 본사로 통하는 길목이기 때문입니다.","JPN":"私たちが雨に打たれながらもここを守る理由は、\\nここが指名手配犯の目的地として有力視された\\nジェフティ・バイオテックの本社に通じる道だからです。","ENG":"The reason we're guarding this place, even in the rain, is because this leads to the corporate headquarters of Jehuty Biotech, a prime candidate for the wanted felon's destination.","TWN":"我們冒著雨守在這裡的原因，是因為這裡是通往傑夫堤生物科技總公司的必經之路，而那裡很可能就是通緝犯的目的地。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"하지만 그보다 중요한 이유가 있죠. 바로 불안에 떠는 시민들의 평안을 위해서입니다.","JPN":"しかし、それよりも重要な理由があります。それは、不安に怯えている市民のためです。","ENG":"But there is an even more important reason. Which is to restore peace for the civilians trembling in trepidation.","TWN":"但其實有另一個更重要的原因，就是保護市民免於恐懼害怕。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"우리가 경솔하게 행동할수록 시민들이 느끼는 방패의 무게도 가벼워집니다.","JPN":"私たちが軽率に行動するほど、市民たちが感じる盾の重さも軽くなります。","ENG":"The greater the levity of our actions, the less trustworthy the people will find us as their shield.","TWN":"我們越是草率行動，市民就會越沒安全感。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그러니 그들이 이 소란 속에서도 안심할 수 있게 흔들림없는 자세를 유지해야 하는 것이죠.","JPN":"ですから、彼らがこの騒ぎの中でも安心できるように揺るぎない姿勢を維持しなければならないのです。","ENG":"Therefore, we must remain strong and steadfast if we are to reassure the public.","TWN":"所以我們才不能輕舉妄動，要一直保持姿勢，這樣在騷動中的市民才能感到安心。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"단장님이 도시관리국의 요청을 받아들인 것이 수배자를 잡아 명예를 드높이기 위해서겠습니까?","JPN":"団長が都市管理局の要請を受け入れたのは、指名手配犯を捕まえて名誉を得るためでしょうか？","ENG":"Do you think the Commander accepted City Managements' request merely to build renown?","TWN":"難道你以為，團長之所以接受城市管理局的請求，目的是要抓住通緝犯提高聲望嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"아닙니다! 자고로 기사의 명예란 기사도를 실천하는…….","JPN":"違います！　騎士の名誉というものは騎士道を実践する……","ENG":"Of course not! To an honorable knight, valor is more worthy than chivalry which-","TWN":"當然不是！自古以來，騎士的榮譽是來自於實踐騎士精神……"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"으아, 이러다 잔소리로 배가 부르겠어…….","JPN":"うわ、このままじゃ小言でお腹がいっぱいになっちゃう……","ENG":"Ugh, she'll drill a hole right through my ears with all that nagging…","TWN":"天啊，再說下去，我光聽你說教就飽啦……"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……그래서! 대체 리브 경은 언제나 철이 들 생각입니까? 그러니 한솔 경이나 에리어스 경은 고사하고 동생들한테까지 동생 취급을 받는 것 아닌가요?","JPN":"……アレン卿はいったいいつ大人になるつもりですか？\\nヤガミ卿やエスクェーデ卿はともかく、\\nそうだから弟たちにまで子ども扱いされるのではないですか？","ENG":"...and that brings me to this point! When will you ever grow up, Dame Liv? This is exactly why even your own younger siblings treat you like a child! Not to mention Sir Hansol and Dame Arius!","TWN":"……所以！莉芙卿，你到底什麼時候才要長大？我們先不說楊瀚卿或埃里奧斯卿，就連在妹妹們的面前，你也沒有一個姊姊的樣子！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"아앗! 약한 구석 찌르는 건 비겁하다구?!","JPN":"ええーそんなストレートに突っ込まれると何も言い返せないじゃない！","ENG":"Ouch! Why do you have to stab me where it hurts? That's not fair!","TWN":"凹嗚！怎麼可以攻擊人家的致命傷？！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"리브 경이 했던 기사 서약을 떠올려 보세요. 마음을 다잡는 데 도움이 될 겁니다.","JPN":"アレン卿が行った騎士の誓約を思い出してください。気持ちを引き締めるのに役立つでしょう。","ENG":"Remember the knight's oath you once made, Dame Liv. It will help you renew that noble spirit in you.","TWN":"莉芙卿，你想想你宣示過的騎士宣言，相信可以幫助你專心的。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};